+/**
+ * Sanitize attributes object by removing event handler attributes.
+ * Prevents XSS attacks through hot spot configuration.
+ * @param {Object} attrs - The attributes object to sanitize
+ * @returns {Object} Sanitized attributes object
+ */
+export function sanitizeAttributes(attrs) {
+    if (attrs == null || typeof attrs !== 'object') {
+        return attrs;
+    }
+    
+    const sanitized = {};
+    for (const key of Object.keys(attrs)) {
+        // Filter out event handler attributes (case-insensitive check for 'on*')
+        if (!key.toLowerCase().startsWith('on')) {
+            sanitized[key] = attrs[key];
+        }
+    }
+    return sanitized;
+}
